// Gemini returns raw 24kHz mono 16-bit PCM (base64). Wrap it in a WAV header so it plays.
const parts = ($json.candidates && $json.candidates[0] && $json.candidates[0].content && $json.candidates[0].content.parts) || [];
const part = parts.find(function (p) { return p.inlineData; });
if (!part) { return [{ json: { error: 'no audio returned', raw: JSON.stringify($json).slice(0, 400) } }]; }
const pcm = Buffer.from(part.inlineData.data, 'base64');
const sampleRate = 24000, channels = 1, bits = 16;
const byteRate = sampleRate * channels * bits / 8;
const blockAlign = channels * bits / 8;
const h = Buffer.alloc(44);
h.write('RIFF', 0); h.writeUInt32LE(36 + pcm.length, 4); h.write('WAVE', 8);
h.write('fmt ', 12); h.writeUInt32LE(16, 16); h.writeUInt16LE(1, 20); h.writeUInt16LE(channels, 22);
h.writeUInt32LE(sampleRate, 24); h.writeUInt32LE(byteRate, 28); h.writeUInt16LE(blockAlign, 32); h.writeUInt16LE(bits, 34);
h.write('data', 36); h.writeUInt32LE(pcm.length, 40);
const wav = Buffer.concat([h, pcm]);
return [{ json: { seconds: Math.round(pcm.length / byteRate * 10) / 10 }, binary: { audio: { data: wav.toString('base64'), mimeType: 'audio/wav', fileName: 'finplaza-voice.wav', fileExtension: 'wav' } } }];
